import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from 'react-query';
import axios from 'axios';
import { Eye, CheckCircle, XCircle, Clock, User, Mail, Phone, MapPin } from 'lucide-react';

const AdminAdoptions = () => {
  const [selectedAdoption, setSelectedAdoption] = useState(null);
  const [filters, setFilters] = useState({ status: '' });
  const [page, setPage] = useState(1);
  const queryClient = useQueryClient();

  const { data, isLoading } = useQuery(
    ['adoptions', filters, page],
    () => {
      const params = new URLSearchParams();
      if (filters.status) params.append('status', filters.status);
      params.append('page', page);
      params.append('limit', 10);

      return axios.get(`/api/adoptions?${params}`).then(res => res.data);
    },
    { keepPreviousData: true }
  );

  const updateStatusMutation = useMutation(
    ({ id, status, notes }) => axios.patch(`/api/adoptions/${id}/status`, { status, notes }),
    {
      onSuccess: () => {
        queryClient.invalidateQueries('adoptions');
        setSelectedAdoption(null);
        alert('Status atualizado com sucesso!');
      },
      onError: () => {
        alert('Erro ao atualizar status');
      }
    }
  );

  const handleStatusUpdate = (adoption, newStatus) => {
    const notes = prompt('Observações (opcional):');
    updateStatusMutation.mutate({
      id: adoption._id,
      status: newStatus,
      notes: notes || ''
    });
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pendente': return 'bg-red-100 text-red-800';
      case 'em análise': return 'bg-yellow-100 text-yellow-800';
      case 'aprovada': return 'bg-green-100 text-green-800';
      case 'rejeitada': return 'bg-gray-100 text-gray-800';
      case 'concluída': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="py-6">
            <h1 className="text-3xl font-bold text-gray-900">Solicitações de Adoção</h1>
            <p className="mt-1 text-sm text-gray-600">
              Gerencie as solicitações de adoção recebidas
            </p>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Filtros */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-8">
          <div className="flex space-x-4">
            <select
              value={filters.status}
              onChange={(e) => setFilters(prev => ({ ...prev, status: e.target.value }))}
              className="input-field"
            >
              <option value="">Todos os status</option>
              <option value="pendente">Pendente</option>
              <option value="em análise">Em Análise</option>
              <option value="aprovada">Aprovada</option>
              <option value="rejeitada">Rejeitada</option>
              <option value="concluída">Concluída</option>
            </select>
          </div>
        </div>

        {/* Lista de Solicitações */}
        {isLoading ? (
          <div className="bg-white rounded-lg shadow-md p-8 text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600 mx-auto"></div>
            <p className="mt-4 text-gray-600">Carregando solicitações...</p>
          </div>
        ) : data?.adoptions?.length > 0 ? (
          <>
            <div className="bg-white shadow-md rounded-lg overflow-hidden">
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Animal
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Solicitante
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Data
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Status
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        Ações
                      </th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {data.adoptions.map((adoption) => (
                      <tr key={adoption._id} className="hover:bg-gray-50">
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center">
                            <div className="flex-shrink-0 h-12 w-12">
                              <img
                                className="h-12 w-12 rounded-lg object-cover"
                                src={adoption.animal?.photos?.[0]?.path ? `/uploads/${adoption.animal.photos[0].path}` : '/placeholder-animal.jpg'}
                                alt={adoption.animal?.name}
                              />
                            </div>
                            <div className="ml-4">
                              <div className="text-sm font-medium text-gray-900">
                                {adoption.animal?.name || 'Animal não encontrado'}
                              </div>
                              <div className="text-sm text-gray-500">
                                {adoption.animal?.species} • {adoption.animal?.age}
                              </div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm font-medium text-gray-900">
                            {adoption.adopter.name}
                          </div>
                          <div className="text-sm text-gray-500">
                            {adoption.adopter.email}
                          </div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                          {new Date(adoption.createdAt).toLocaleDateString('pt-BR')}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <span className={`inline-flex px-2 py-1 text-xs font-medium rounded-full ${getStatusColor(adoption.status)}`}>
                            {adoption.status}
                          </span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                          <div className="flex space-x-2">
                            <button
                              onClick={() => setSelectedAdoption(adoption)}
                              className="text-blue-600 hover:text-blue-900"
                              title="Ver detalhes"
                            >
                              <Eye className="h-4 w-4" />
                            </button>
                            {adoption.status === 'pendente' && (
                              <button
                                onClick={() => handleStatusUpdate(adoption, 'em análise')}
                                className="text-yellow-600 hover:text-yellow-900"
                                title="Colocar em análise"
                              >
                                <Clock className="h-4 w-4" />
                              </button>
                            )}
                            {['pendente', 'em análise'].includes(adoption.status) && (
                              <>
                                <button
                                  onClick={() => handleStatusUpdate(adoption, 'aprovada')}
                                  className="text-green-600 hover:text-green-900"
                                  title="Aprovar"
                                >
                                  <CheckCircle className="h-4 w-4" />
                                </button>
                                <button
                                  onClick={() => handleStatusUpdate(adoption, 'rejeitada')}
                                  className="text-red-600 hover:text-red-900"
                                  title="Rejeitar"
                                >
                                  <XCircle className="h-4 w-4" />
                                </button>
                              </>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Paginação */}
            {data.pagination.pages > 1 && (
              <div className="flex justify-center mt-8">
                <div className="flex space-x-2">
                  <button
                    onClick={() => setPage(page - 1)}
                    disabled={page === 1}
                    className="px-3 py-2 border border-gray-300 rounded-md disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50"
                  >
                    Anterior
                  </button>

                  {[...Array(Math.min(5, data.pagination.pages))].map((_, i) => {
                    const pageNum = i + 1;
                    return (
                      <button
                        key={pageNum}
                        onClick={() => setPage(pageNum)}
                        className={`px-3 py-2 border rounded-md ${
                          page === pageNum
                            ? 'bg-primary-600 text-white border-primary-600'
                            : 'border-gray-300 hover:bg-gray-50'
                        }`}
                      >
                        {pageNum}
                      </button>
                    );
                  })}

                  <button
                    onClick={() => setPage(page + 1)}
                    disabled={page === data.pagination.pages}
                    className="px-3 py-2 border border-gray-300 rounded-md disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50"
                  >
                    Próxima
                  </button>
                </div>
              </div>
            )}
          </>
        ) : (
          <div className="bg-white rounded-lg shadow-md p-12 text-center">
            <User className="h-16 w-16 text-gray-400 mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-gray-900 mb-2">
              Nenhuma solicitação encontrada
            </h3>
            <p className="text-gray-600">
              As solicitações de adoção aparecerão aqui quando forem enviadas
            </p>
          </div>
        )}
      </div>

      {/* Modal de Detalhes */}
      {selectedAdoption && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-11/12 md:w-3/4 lg:w-1/2 shadow-lg rounded-md bg-white">
            <div className="mt-3">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-medium text-gray-900">
                  Detalhes da Solicitação
                </h3>
                <button
                  onClick={() => setSelectedAdoption(null)}
                  className="text-gray-400 hover:text-gray-600"
                >
                  ✕
                </button>
              </div>

              <div className="space-y-6">
                {/* Animal */}
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Animal</h4>
                  <div className="flex items-center space-x-4 p-4 bg-gray-50 rounded-lg">
                    <img
                      src={selectedAdoption.animal?.photos?.[0]?.path ? `/uploads/${selectedAdoption.animal.photos[0].path}` : '/placeholder-animal.jpg'}
                      alt={selectedAdoption.animal?.name}
                      className="w-16 h-16 rounded-lg object-cover"
                    />
                    <div>
                      <p className="font-medium">{selectedAdoption.animal?.name}</p>
                      <p className="text-sm text-gray-600">
                        {selectedAdoption.animal?.species} • {selectedAdoption.animal?.age} • {selectedAdoption.animal?.size}
                      </p>
                    </div>
                  </div>
                </div>

                {/* Dados do Solicitante */}
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Dados do Solicitante</h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="flex items-center space-x-2">
                      <User className="h-4 w-4 text-gray-400" />
                      <span className="text-sm">{selectedAdoption.adopter.name}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <Mail className="h-4 w-4 text-gray-400" />
                      <span className="text-sm">{selectedAdoption.adopter.email}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <Phone className="h-4 w-4 text-gray-400" />
                      <span className="text-sm">{selectedAdoption.adopter.phone}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <span className="text-sm">CPF: {selectedAdoption.adopter.cpf}</span>
                    </div>
                  </div>
                </div>

                {/* Endereço */}
                {selectedAdoption.adopter.address && (
                  <div>
                    <h4 className="font-medium text-gray-900 mb-2">Endereço</h4>
                    <div className="flex items-start space-x-2">
                      <MapPin className="h-4 w-4 text-gray-400 mt-1" />
                      <div className="text-sm">
                        {selectedAdoption.adopter.address.street && (
                          <p>{selectedAdoption.adopter.address.street}</p>
                        )}
                        <p>{selectedAdoption.adopter.address.city}, {selectedAdoption.adopter.address.state}</p>
                      </div>
                    </div>
                  </div>
                )}

                {/* Moradia */}
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Moradia</h4>
                  <div className="text-sm space-y-1">
                    <p>Tipo: {selectedAdoption.housing.type}</p>
                    <p>Possui quintal: {selectedAdoption.housing.hasYard ? 'Sim' : 'Não'}</p>
                    <p>É alugada: {selectedAdoption.housing.isRented ? 'Sim' : 'Não'}</p>
                    {selectedAdoption.housing.isRented && (
                      <p>Autorização do proprietário: {selectedAdoption.housing.ownerConsent ? 'Sim' : 'Não'}</p>
                    )}
                  </div>
                </div>

                {/* Motivação */}
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Motivação</h4>
                  <p className="text-sm text-gray-700 bg-gray-50 p-3 rounded-lg">
                    {selectedAdoption.motivation}
                  </p>
                </div>

                {/* Experiência */}
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Experiência com Animais</h4>
                  <div className="text-sm space-y-2">
                    <p>Já teve animais: {selectedAdoption.experience.hadPetsBefore ? 'Sim' : 'Não'}</p>
                    {selectedAdoption.experience.currentPets && (
                      <div>
                        <p className="font-medium">Animais atuais:</p>
                        <p className="text-gray-700">{selectedAdoption.experience.currentPets}</p>
                      </div>
                    )}
                    {selectedAdoption.experience.petCareExperience && (
                      <div>
                        <p className="font-medium">Experiência:</p>
                        <p className="text-gray-700">{selectedAdoption.experience.petCareExperience}</p>
                      </div>
                    )}
                  </div>
                </div>

                {/* Status e Observações */}
                <div>
                  <h4 className="font-medium text-gray-900 mb-2">Status</h4>
                  <div className="flex items-center space-x-4">
                    <span className={`inline-flex px-3 py-1 text-sm font-medium rounded-full ${getStatusColor(selectedAdoption.status)}`}>
                      {selectedAdoption.status}
                    </span>
                    <span className="text-sm text-gray-500">
                      {new Date(selectedAdoption.createdAt).toLocaleDateString('pt-BR')}
                    </span>
                  </div>
                  {selectedAdoption.notes && (
                    <div className="mt-2">
                      <p className="text-sm font-medium">Observações:</p>
                      <p className="text-sm text-gray-700">{selectedAdoption.notes}</p>
                    </div>
                  )}
                </div>

                {/* Ações */}
                {['pendente', 'em análise'].includes(selectedAdoption.status) && (
                  <div className="flex space-x-3 pt-4 border-t">
                    <button
                      onClick={() => handleStatusUpdate(selectedAdoption, 'aprovada')}
                      className="btn-primary flex-1"
                    >
                      Aprovar
                    </button>
                    <button
                      onClick={() => handleStatusUpdate(selectedAdoption, 'rejeitada')}
                      className="btn-secondary flex-1"
                    >
                      Rejeitar
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminAdoptions;
